/**
 * Documentation Generator (Per-Model)
 *
 * Generates Docusaurus-compatible Markdown documentation from Prisma schema.
 * Produces:
 *   - Per-model reference pages (fields, types, relations)
 *   - API endpoint documentation
 *   - SDK usage examples (stores, types, hooks)
 *   - Overview index page
 *
 * Output is designed for Docusaurus 3.9 with autogenerated sidebars.
 */

import type { PrismaModel, PrismaField } from './prisma-generator'
import { getScalarFields, getRelationFields, getIdField, toCamelCase, toKebabCase } from './prisma-generator'

// ============================================================================
// Types
// ============================================================================

interface PrismaEnum {
  name: string
  values: { name: string }[]
}

export interface GeneratedDocFile {
  /** Relative file path (e.g., 'docs/models/workspace.md') */
  path: string
  /** File content (Markdown) */
  content: string
  /** If true, don't overwrite existing file */
  skipIfExists?: boolean
}

export interface DocsGeneratorConfig {
  /** Project name for the docs site (default: 'My App') */
  projectName?: string
  /** Base API path (default: '/api') */
  apiBasePath?: string
  /** Which generated output types exist (to tailor examples) */
  generatedOutputs?: ('routes' | 'types' | 'stores' | 'mst')[]
}

// ============================================================================
// Utilities
// ============================================================================

/**
 * Convert model name to route path (kebab-case, plural)
 */
function toRoutePath(name: string): string {
  const kebab = toKebabCase(name)
  if (kebab.endsWith('y')) return kebab.slice(0, -1) + 'ies'
  if (kebab.endsWith('s') || kebab.endsWith('x') || kebab.endsWith('ch') || kebab.endsWith('sh')) {
    return kebab + 'es'
  }
  return kebab + 's'
}

/**
 * Map Prisma field type to a human-readable TypeScript type
 */
function mapFieldType(field: PrismaField): string {
  if (field.kind === 'enum') return field.type
  if (field.kind === 'object') return field.isList ? `${field.type}[]` : field.type

  switch (field.type) {
    case 'String': return 'string'
    case 'Int':
    case 'Float':
    case 'Decimal': return 'number'
    case 'Boolean': return 'boolean'
    case 'DateTime': return 'Date'
    case 'Json': return 'Record<string, unknown>'
    case 'BigInt': return 'bigint'
    case 'Bytes': return 'Buffer'
    default: return 'unknown'
  }
}

/**
 * Describe field attributes in a human-readable way
 */
function describeField(field: PrismaField): string {
  const parts: string[] = []
  if (field.isId) parts.push('Primary key')
  if (field.isUnique) parts.push('Unique')
  if (!field.isRequired) parts.push('Nullable')
  if (field.hasDefaultValue) parts.push('Auto-generated')
  if (field.kind === 'enum') parts.push(`Enum`)
  if (field.relationName) parts.push(`Relation`)
  return parts.join(', ') || '—'
}

// ============================================================================
// Model Documentation
// ============================================================================

/**
 * Generate a Docusaurus Markdown page for a single model
 */
export function generateModelDoc(
  model: PrismaModel,
  allModels: PrismaModel[],
  enums: PrismaEnum[],
  config: DocsGeneratorConfig = {},
): GeneratedDocFile {
  const name = model.name
  const kebab = toKebabCase(name)
  const camel = toCamelCase(name)
  const routePath = toRoutePath(name)
  const apiBase = config.apiBasePath || '/api'
  const scalarFields = getScalarFields(model)
  const relationFields = getRelationFields(model)
  const idField = getIdField(model)

  const lines: string[] = []

  // Frontmatter
  lines.push('---')
  lines.push(`title: ${name}`)
  lines.push(`sidebar_label: ${name}`)
  lines.push(`description: API reference and usage guide for the ${name} model.`)
  lines.push('---')
  lines.push('')

  // Title
  lines.push(`# ${name}`)
  lines.push('')

  // Summary
  const fieldCount = scalarFields.length
  const relationCount = relationFields.length
  lines.push(`The \`${name}\` model has **${fieldCount}** fields${relationCount > 0 ? ` and **${relationCount}** relation${relationCount !== 1 ? 's' : ''}` : ''}.`)
  lines.push('')

  // ── Fields table ──────────────────────────────────────────────────────
  lines.push('## Fields')
  lines.push('')
  lines.push('| Field | Type | Required | Attributes |')
  lines.push('|-------|------|----------|------------|')

  for (const field of scalarFields) {
    const tsType = mapFieldType(field)
    const required = field.isRequired ? 'Yes' : 'No'
    const attrs = describeField(field)
    lines.push(`| \`${field.name}\` | \`${tsType}\` | ${required} | ${attrs} |`)
  }
  lines.push('')

  // ── Enums used by this model ──────────────────────────────────────────
  const modelEnumTypes = new Set(
    model.fields.filter(f => f.kind === 'enum').map(f => f.type)
  )
  if (modelEnumTypes.size > 0) {
    const relevantEnums = enums.filter(e => modelEnumTypes.has(e.name))
    if (relevantEnums.length > 0) {
      lines.push('## Enums')
      lines.push('')
      for (const enumDef of relevantEnums) {
        lines.push(`### ${enumDef.name}`)
        lines.push('')
        lines.push('| Value |')
        lines.push('|-------|')
        for (const val of enumDef.values) {
          lines.push(`| \`${val.name}\` |`)
        }
        lines.push('')
      }
    }
  }

  // ── Relations ─────────────────────────────────────────────────────────
  if (relationFields.length > 0) {
    lines.push('## Relations')
    lines.push('')
    lines.push('| Relation | Type | Kind |')
    lines.push('|----------|------|------|')

    for (const rel of relationFields) {
      const kind = rel.isList ? 'Has many' : 'Belongs to'
      const type = rel.isList ? `${rel.type}[]` : rel.type
      // Check if the related model is in our generated set
      const relatedModel = allModels.find(m => m.name === rel.type)
      const typeDisplay = relatedModel
        ? `[\`${type}\`](../models/${toKebabCase(rel.type)})`
        : `\`${type}\``
      lines.push(`| \`${rel.name}\` | ${typeDisplay} | ${kind} |`)
    }
    lines.push('')
  }

  // ── TypeScript Types ──────────────────────────────────────────────────
  lines.push('## TypeScript Types')
  lines.push('')
  lines.push('The following types are auto-generated:')
  lines.push('')
  lines.push('```typescript')
  // Main type
  lines.push(`interface ${name}Type {`)
  for (const field of scalarFields) {
    const tsType = mapFieldType(field)
    const opt = !field.isRequired && !field.isId ? '?' : ''
    const nullable = !field.isRequired ? ' | null' : ''
    lines.push(`  ${field.name}${opt}: ${tsType}${!opt && nullable ? nullable : ''}`)
  }
  lines.push('}')
  lines.push('')

  // Create input
  lines.push(`interface ${name}CreateInput {`)
  for (const field of scalarFields) {
    if (field.isId && field.hasDefaultValue) continue
    if (field.name === 'createdAt' || field.name === 'updatedAt') continue
    const tsType = mapFieldType(field)
    const opt = !field.isRequired || field.hasDefaultValue ? '?' : ''
    lines.push(`  ${field.name}${opt}: ${tsType}`)
  }
  lines.push('}')
  lines.push('')

  // Update input
  lines.push(`interface ${name}UpdateInput {`)
  for (const field of scalarFields) {
    if (field.isId) continue
    if (field.name === 'createdAt' || field.name === 'updatedAt') continue
    const tsType = mapFieldType(field)
    lines.push(`  ${field.name}?: ${tsType}`)
  }
  lines.push('}')
  lines.push('```')
  lines.push('')

  // ── API Endpoints ─────────────────────────────────────────────────────
  if (idField) {
    lines.push('## API Endpoints')
    lines.push('')
    lines.push(`All endpoints are relative to \`${apiBase}/${routePath}\`.`)
    lines.push('')

    // LIST
    lines.push('### List all')
    lines.push('')
    lines.push('```http')
    lines.push(`GET ${apiBase}/${routePath}`)
    lines.push('```')
    lines.push('')
    lines.push('**Query parameters:**')
    lines.push('')
    lines.push('| Parameter | Type | Description |')
    lines.push('|-----------|------|-------------|')
    lines.push('| `limit` | `number` | Max items to return |')
    lines.push('| `offset` | `number` | Items to skip (pagination) |')
    // Add filterable fields
    for (const field of scalarFields) {
      if (field.isId) continue
      if (field.name === 'createdAt' || field.name === 'updatedAt') continue
      lines.push(`| \`${field.name}\` | \`${mapFieldType(field)}\` | Filter by ${field.name} |`)
    }
    lines.push('')
    lines.push('**Response:** `200 OK`')
    lines.push('')
    lines.push('```json')
    lines.push(`[{ ${scalarFields.slice(0, 3).map(f => `"${f.name}": ...`).join(', ')}, ... }]`)
    lines.push('```')
    lines.push('')

    // GET by ID
    lines.push('### Get by ID')
    lines.push('')
    lines.push('```http')
    lines.push(`GET ${apiBase}/${routePath}/:${idField.name}`)
    lines.push('```')
    lines.push('')
    lines.push('**Response:** `200 OK` | `404 Not Found`')
    lines.push('')

    // CREATE
    lines.push('### Create')
    lines.push('')
    lines.push('```http')
    lines.push(`POST ${apiBase}/${routePath}`)
    lines.push('```')
    lines.push('')
    lines.push('**Request body:**')
    lines.push('')
    lines.push('```json')
    lines.push('{')
    const createFields = scalarFields.filter(f => {
      if (f.isId && f.hasDefaultValue) return false
      if (f.name === 'createdAt' || f.name === 'updatedAt') return false
      return true
    })
    for (let i = 0; i < createFields.length; i++) {
      const f = createFields[i]
      const example = getExampleValue(f)
      const comma = i < createFields.length - 1 ? ',' : ''
      const optional = !f.isRequired || f.hasDefaultValue ? '  // optional' : ''
      lines.push(`  "${f.name}": ${example}${comma}${optional}`)
    }
    lines.push('}')
    lines.push('```')
    lines.push('')
    lines.push('**Response:** `201 Created`')
    lines.push('')

    // UPDATE
    lines.push('### Update')
    lines.push('')
    lines.push('```http')
    lines.push(`PATCH ${apiBase}/${routePath}/:${idField.name}`)
    lines.push('```')
    lines.push('')
    lines.push('**Request body:** Any subset of fields from `' + name + 'UpdateInput`.')
    lines.push('')
    lines.push('**Response:** `200 OK` | `404 Not Found`')
    lines.push('')

    // DELETE
    lines.push('### Delete')
    lines.push('')
    lines.push('```http')
    lines.push(`DELETE ${apiBase}/${routePath}/:${idField.name}`)
    lines.push('```')
    lines.push('')
    lines.push('**Response:** `200 OK` | `404 Not Found`')
    lines.push('')
  }

  // ── Store Usage ───────────────────────────────────────────────────────
  lines.push('## Store Usage')
  lines.push('')
  lines.push(`Import the generated store and types to interact with \`${name}\` records:`)
  lines.push('')
  lines.push('```typescript')
  lines.push(`import { ${camel}Store } from './generated/${kebab}.store'`)
  lines.push(`import type { ${name}Type, ${name}CreateInput } from './generated/${kebab}.types'`)
  lines.push('')
  lines.push('// List all')
  lines.push(`const items = await ${camel}Store.fetchAll()`)
  lines.push('')
  lines.push('// Get by ID')
  lines.push(`const item = await ${camel}Store.fetchById('some-id')`)
  lines.push('')
  lines.push('// Create')
  lines.push(`const newItem = await ${camel}Store.create({`)
  for (const f of createFields(scalarFields)) {
    lines.push(`  ${f.name}: ${getExampleValueTS(f)},`)
  }
  lines.push('})')
  lines.push('')
  lines.push('// Update')
  lines.push(`await ${camel}Store.update('some-id', { /* fields to update */ })`)
  lines.push('')
  lines.push('// Delete')
  lines.push(`await ${camel}Store.delete('some-id')`)
  lines.push('```')
  lines.push('')

  // ── Hooks ─────────────────────────────────────────────────────────────
  if (idField) {
    lines.push('## Hooks')
    lines.push('')
    lines.push(`You can customize server-side behavior for \`${name}\` by editing the hooks file:`)
    lines.push('')
    lines.push('```typescript')
    lines.push(`// ${kebab}.hooks.ts`)
    lines.push(`import type { ${name}Hooks } from './${kebab}.hooks'`)
    lines.push('')
    lines.push(`export const hooks: ${name}Hooks = {`)
    lines.push('  beforeList: async (ctx) => {')
    lines.push('    // Add custom filtering')
    lines.push('    return { ok: true, data: { where: { /* ... */ } } }')
    lines.push('  },')
    lines.push('  beforeCreate: async (ctx) => {')
    lines.push('    // Validate or transform input before creation')
    lines.push('    return { ok: true, data: ctx.body }')
    lines.push('  },')
    lines.push('  afterCreate: async (item, ctx) => {')
    lines.push('    // Side effects after creation (notifications, logging, etc.)')
    lines.push('  },')
    lines.push('}')
    lines.push('```')
    lines.push('')

    lines.push('### Available Hook Points')
    lines.push('')
    lines.push('| Hook | Trigger | Use Case |')
    lines.push('|------|---------|----------|')
    lines.push('| `beforeList` | Before fetching list | Add filters, access control |')
    lines.push('| `beforeGet` | Before fetching by ID | Access control |')
    lines.push('| `beforeCreate` | Before inserting | Validate, transform, set defaults |')
    lines.push('| `afterCreate` | After inserting | Notifications, audit logging |')
    lines.push('| `beforeUpdate` | Before updating | Validate, prevent field changes |')
    lines.push('| `afterUpdate` | After updating | Sync, notifications |')
    lines.push('| `beforeDelete` | Before deleting | Access control, soft-delete |')
    lines.push('| `afterDelete` | After deleting | Cleanup, audit logging |')
    lines.push('')
  }

  return {
    path: `docs/models/${kebab}.md`,
    content: lines.join('\n'),
  }
}

// ============================================================================
// Overview Page
// ============================================================================

/**
 * Generate the overview/index page for models
 */
export function generateModelsIndex(
  models: PrismaModel[],
  config: DocsGeneratorConfig = {},
): GeneratedDocFile {
  const projectName = config.projectName || 'My App'
  const lines: string[] = []

  lines.push('---')
  lines.push('title: Models Overview')
  lines.push('sidebar_label: Overview')
  lines.push('sidebar_position: 1')
  lines.push('---')
  lines.push('')
  lines.push('# Models Overview')
  lines.push('')
  lines.push(`This section documents all **${models.length}** models generated from the Prisma schema.`)
  lines.push('')
  lines.push('## Models')
  lines.push('')
  lines.push('| Model | Fields | Relations | Description |')
  lines.push('|-------|--------|-----------|-------------|')

  for (const model of models) {
    const scalarCount = getScalarFields(model).length
    const relationCount = getRelationFields(model).length
    const kebab = toKebabCase(model.name)
    lines.push(`| [**${model.name}**](./models/${kebab}) | ${scalarCount} | ${relationCount} | ${model.name} model |`)
  }

  lines.push('')
  lines.push('## Quick Start')
  lines.push('')
  lines.push('Each model page includes:')
  lines.push('')
  lines.push('- **Fields** — Complete field reference with types and attributes')
  lines.push('- **Relations** — How this model connects to others')
  lines.push('- **TypeScript Types** — Generated `Type`, `CreateInput`, and `UpdateInput` interfaces')
  lines.push('- **API Endpoints** — REST endpoints with request/response examples')
  lines.push('- **Store Usage** — How to use the generated client-side store')
  lines.push('- **Hooks** — How to customize server-side CRUD behavior')
  lines.push('')

  return {
    path: 'docs/models-overview.md',
    content: lines.join('\n'),
  }
}

// ============================================================================
// API Overview Page
// ============================================================================

/**
 * Generate an API overview page listing all endpoints
 */
export function generateApiOverview(
  models: PrismaModel[],
  config: DocsGeneratorConfig = {},
): GeneratedDocFile {
  const apiBase = config.apiBasePath || '/api'
  const lines: string[] = []

  lines.push('---')
  lines.push('title: API Reference')
  lines.push('sidebar_label: API Reference')
  lines.push('sidebar_position: 2')
  lines.push('---')
  lines.push('')
  lines.push('# API Reference')
  lines.push('')
  lines.push('Complete REST API reference for all generated endpoints.')
  lines.push('')
  lines.push('## Endpoints')
  lines.push('')
  lines.push('| Method | Path | Description |')
  lines.push('|--------|------|-------------|')

  for (const model of models) {
    const idField = getIdField(model)
    if (!idField) continue

    const routePath = toRoutePath(model.name)
    const kebab = toKebabCase(model.name)

    lines.push(`| \`GET\` | \`${apiBase}/${routePath}\` | [List all ${model.name}s](./models/${kebab}#list-all) |`)
    lines.push(`| \`GET\` | \`${apiBase}/${routePath}/:${idField.name}\` | [Get ${model.name} by ID](./models/${kebab}#get-by-id) |`)
    lines.push(`| \`POST\` | \`${apiBase}/${routePath}\` | [Create ${model.name}](./models/${kebab}#create) |`)
    lines.push(`| \`PATCH\` | \`${apiBase}/${routePath}/:${idField.name}\` | [Update ${model.name}](./models/${kebab}#update) |`)
    lines.push(`| \`DELETE\` | \`${apiBase}/${routePath}/:${idField.name}\` | [Delete ${model.name}](./models/${kebab}#delete) |`)
  }

  lines.push('')
  lines.push('## Authentication')
  lines.push('')
  lines.push('All endpoints support authentication via the `auth` context. When a user is authenticated,')
  lines.push('`ctx.userId` is available in hooks for access control.')
  lines.push('')
  lines.push('## Query Parameters')
  lines.push('')
  lines.push('List endpoints accept the following common query parameters:')
  lines.push('')
  lines.push('| Parameter | Type | Description |')
  lines.push('|-----------|------|-------------|')
  lines.push('| `limit` | `number` | Maximum number of items to return |')
  lines.push('| `offset` | `number` | Number of items to skip (for pagination) |')
  lines.push('')
  lines.push('Additionally, any model field can be used as a filter parameter.')
  lines.push('')
  lines.push('## Error Responses')
  lines.push('')
  lines.push('| Status | Description |')
  lines.push('|--------|-------------|')
  lines.push('| `400 Bad Request` | Invalid input or hook rejection |')
  lines.push('| `404 Not Found` | Resource not found |')
  lines.push('| `500 Internal Server Error` | Server error |')
  lines.push('')

  return {
    path: 'docs/api-reference.md',
    content: lines.join('\n'),
  }
}

// ============================================================================
// Category metadata files (for Docusaurus sidebar)
// ============================================================================

export function generateModelsCategoryMeta(): GeneratedDocFile {
  return {
    path: 'docs/models/_category_.json',
    content: JSON.stringify({
      label: 'Models',
      position: 3,
      collapsed: false,
      link: null,
    }, null, 2) + '\n',
  }
}

// ============================================================================
// All docs generation
// ============================================================================

/**
 * Generate all documentation files for the given models
 */
export function generateDocs(
  models: PrismaModel[],
  enums: PrismaEnum[],
  config: DocsGeneratorConfig = {},
): GeneratedDocFile[] {
  const files: GeneratedDocFile[] = []

  // Overview page
  files.push(generateModelsIndex(models, config))

  // API reference page
  files.push(generateApiOverview(models, config))

  // Category metadata for sidebar
  files.push(generateModelsCategoryMeta())

  // Per-model pages
  for (const model of models) {
    files.push(generateModelDoc(model, models, enums, config))
  }

  return files
}

// ============================================================================
// Helpers
// ============================================================================

/**
 * Get example JSON value for a field
 */
function getExampleValue(field: PrismaField): string {
  if (field.kind === 'enum') return `"VALUE"`

  switch (field.type) {
    case 'String': return field.name.includes('email') ? '"user@example.com"'
      : field.name.includes('url') || field.name.includes('Url') ? '"https://example.com"'
      : field.name === 'name' ? `"Example ${field.name}"`
      : `"string"`
    case 'Int': return '1'
    case 'Float':
    case 'Decimal': return '1.0'
    case 'Boolean': return 'true'
    case 'DateTime': return '"2025-01-01T00:00:00Z"'
    case 'Json': return '{}'
    default: return 'null'
  }
}

/**
 * Get example TypeScript value for a field
 */
function getExampleValueTS(field: PrismaField): string {
  if (field.kind === 'enum') return `'VALUE'`

  switch (field.type) {
    case 'String': return field.name.includes('email') ? "'user@example.com'"
      : field.name.includes('url') || field.name.includes('Url') ? "'https://example.com'"
      : field.name === 'name' ? `'Example'`
      : `'...'`
    case 'Int': return '1'
    case 'Float':
    case 'Decimal': return '1.0'
    case 'Boolean': return 'true'
    case 'DateTime': return 'new Date()'
    case 'Json': return '{}'
    default: return 'null'
  }
}

/**
 * Filter to only "create-worthy" fields
 */
function createFields(scalarFields: PrismaField[]): PrismaField[] {
  return scalarFields.filter(f => {
    if (f.isId && f.hasDefaultValue) return false
    if (f.name === 'createdAt' || f.name === 'updatedAt') return false
    return f.isRequired && !f.hasDefaultValue
  })
}
